import { describe, it } from "vitest";

describe("MHPCO Claim Office", () => {
  // --- Quote: empty and single items ---
  it.todo("empty item list yields premium of 5 G (only processing fee)");
  it.todo("single sword for established customer yields 105 G");
  it.todo("single amulet for established customer yields 65 G");
  it.todo("single staff for established customer yields 85 G");
  it.todo("single potion for established customer yields 45 G");
  it.todo("single component (rune) for established customer yields 30 G");

  // --- Components and blocks ---
  it.todo("2 runes yield base premium 50 G");
  it.todo("3 alike runes form a block with base premium 60 G");
  it.todo("4 runes do not form a block (base premium 100 G)");
  it.todo("7 runes form one block of 3 plus 4 singles (base premium 160 G)");
  it.todo("2 runes + 1 moonstone do not form a block (base premium 75 G)");
  it.todo("3 runes + 3 moonstones form two separate blocks (base premium 120 G)");

  // --- Multi-item policy ---
  it.todo("sword + amulet yields base premium 160 G");

  // --- Premium modifiers ---
  it.todo("cursed sword adds 50% surcharge on the cursed item only");
  it.todo("sword with enchantment 5 adds 30% high-enchantment surcharge");
  it.todo("sword with enchantment 4 does not add high-enchantment surcharge");
  it.todo("customer with exactly 2 years receives 20% loyalty discount");
  it.todo("first insurance surcharge of 10% applies per item in a quote");
  it.todo("follow-up contract receives 15% policy-wide discount");
  it.todo("modifier scope: cursed sword + plain amulet → curse surcharge on cursed item only");

  // --- Rounding ---
  it.todo("premium rounds up to whole G in MHPCO's favor (197.5 → 198)");

  // --- Integration examples ---
  it.todo("newcomer with a cursed sword (steel, ench 3) yields premium 165 G");
  it.todo("long-standing customer's second contract: cursed enchanted sword yields 160 G");

  // --- Claim: standard payouts ---
  it.todo("standard sword damage 500 G yields payout 400 G (deductible 100)");
  it.todo("rune damage 200 G yields payout 100 G (no special clauses)");
  it.todo("dragon-material sword damage 800 G yields payout 700 G (full minus deductible)");
  it.todo("high-enchantment sword (ench 9) damage 1000 G yields payout 400 G (50% then deductible)");
  it.todo("dragon-material sword ench 9 damage 1000 G yields payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword ench 8 damage 1000 G yields payout 400 G (50% then deductible)");

  // --- Multiple damages and deductible ---
  it.todo("damaged sword (500 G) and amulet (300 G) yield payout 600 G (deductible per item)");
  it.todo("multiple items of same type: two swords each damaged in one incident");

  // --- Cap exhaustion ---
  it.todo("sword cap 2000 G, claim 1500 G then 1500 G → payouts 1400 G, 600 G");
  it.todo("payout rounds down to whole G (350.5 → 350)");

  // --- Errors ---
  it.todo("quote with unknown item type throws error");
  it.todo("claim referencing item not in policy throws error");
  it.todo("claim with negative damage amount throws error");
  it.todo("claim with more damages of a type than insured throws error");
});

